517	export function getPortlessMfeDevOrigins({
518		name,
519		tld,
520		cwd = process.cwd(),
521		env = process.env,
522		config,
523		configPath,
524		includeWildcard = true,
525		includePort = false,
526		allowMissingConfig = false,
527	}: GetPortlessMfeDevOriginsOptions = {}): string[] {
528		const normalized = resolveOptionalPackageConfigForApi({ cwd, config, configPath });
529	
530		if (!normalized && !name) {
531			if (allowMissingConfig) {
532				return [];
533			}
534	
535			throw new Error(
536				`Could not find ${CONFIG_FILENAMES.join(" or ")} from ${cwd}`,
537			);
538		}
539	
540		const fallbackConfig = normalized ?? normalizePackageConfig({}, { root: cwd });
541		const portlessName = name ?? fallbackConfig.portless.name;
542		const portlessTld = tld ?? env.PORTLESS_TLD ?? fallbackConfig.portless.tld;
543		const portlessPort = parsePort(env.PORTLESS_PORT) ?? fallbackConfig.portless.port;
544		const portlessNames = [portlessName];
545	
546		if (normalized) {
547			const sourceConfig = readMicrofrontendsConfigIfAvailable(normalized);
548			const originConfig = {
549				...normalized,
550				portless: {
551					...normalized.portless,
552					name: portlessName,
553				},
554			};
555			for (const [appName, appConfig] of Object.entries(sourceConfig?.applications ?? {})) {
556				portlessNames.push(resolveApplicationPortlessName(appName, appConfig, originConfig));
557			}
558		}
559	
560		return unique(
561			portlessNames.flatMap((value) => {
562				const host = `${value}.${portlessTld}`;
563				const hosts = includePort === "both"
564					? [host, `${host}:${portlessPort}`]
565					: [`${host}${includePort ? `:${portlessPort}` : ""}`];
566	
567				return hosts.flatMap((originHost) => (
568					includeWildcard ? [originHost, `*.${originHost}`] : [originHost]
569				));
570			}),
571		);
572	}
573	
574	export async function createVercelMicrofrontendsDevConfig({
575		cwd = process.cwd(),
576		env = process.env,
577		config,
578		sourceConfigPath,
579		appDirs,
