function portlessUrlMatchesName(url: string, name: string, tld: string): boolean {
	try {
		const host = new URL(url).hostname;
		const baseHost = `${name}.${tld}`;
		return host === baseHost || host.endsWith(`.${baseHost}`);
	} catch {
		return false;
	}
}

